class OptionsController{constructor(){this.init()}async init(){await this.loadSettings(),this.bindEvents()}async loadSettings(){const e=await chrome.storage.local.get(null),t=e.defaultFormat||"markdown",o=document.querySelector(`input[name="defaultFormat"][value="${t}"]`);o&&(o.checked=!0);const c=document.querySelector("#includeTimestamp"),a=document.querySelector("#includeMetadata"),n=document.querySelector("#autoMerge"),d=document.querySelector("#filenameTemplate"),s=document.querySelector("#debugMode");c&&(c.checked=!1!==e.includeTimestamp),a&&(a.checked=!1!==e.includeMetadata),n&&(n.checked=e.autoMerge||!1),d&&(d.value=e.filenameTemplate||"{title}_{date}"),s&&(s.checked=e.debugMode||!1)}bindEvents(){document.querySelector("#saveBtn")?.addEventListener("click",()=>{this.saveSettings()}),document.querySelector("#resetBtn")?.addEventListener("click",()=>{this.resetSettings()})}async saveSettings(){const e={defaultFormat:document.querySelector('input[name="defaultFormat"]:checked')?.value,includeTimestamp:document.querySelector("#includeTimestamp")?.checked,includeMetadata:document.querySelector("#includeMetadata")?.checked,autoMerge:document.querySelector("#autoMerge")?.checked,filenameTemplate:document.querySelector("#filenameTemplate")?.value,debugMode:document.querySelector("#debugMode")?.checked};await chrome.storage.local.set(e),this.showToast("设置已保存","success")}async resetSettings(){await chrome.storage.local.clear(),await this.loadSettings(),this.showToast("已重置为默认设置","info")}showToast(e,t="info"){const o=document.querySelector(".toast");o&&o.remove();const c=document.createElement("div");c.className=`toast toast-${t}`,c.textContent=e,document.body.appendChild(c),setTimeout(()=>c.remove(),2e3)}}document.addEventListener("DOMContentLoaded",()=>{new OptionsController});